# Build JSON object per schema
citations = []
for item in results:
    start,end,span,canon,valid,typ,ref = item
    entry = {
        "span_start": start,
        "span_end": end,
        "span_text": span,
        "citation_type": "Aya" if typ=='Aya' else "Hadeeth",
        "is_valid": bool(valid),
        "aya_reference": {},
        "hadeeth_reference": {},
        "corrected_text": "",
        "completely_invalid": False
    }
    if typ=='Aya':
        sura_name, sura_num, aya_num = ref
        entry["aya_reference"] = {"sura_name": sura_name, "sura_number": sura_num, "aya_number": aya_num}
        if valid:
            entry["corrected_text"] = span
            entry["completely_invalid"] = False
        else:
            entry["corrected_text"] = canon if canon else "خطأ"
            entry["completely_invalid"] = False if canon else True
    else:
        # hadith
        entry["hadeeth_reference"] = {}
        entry["corrected_text"] = "خطأ"
        entry["completely_invalid"] = True
    citations.append(entry)

output = {"citations": citations}
import json, textwrap
json.dumps(output, ensure_ascii=False)[:1000]
